<script setup>
defineProps({
  title: { type: String, default: '消息' },
  showRefresh: { type: Boolean, default: true },
  loading: { type: Boolean, default: false },
})
defineEmits(['refresh'])
</script>

<template>
  <header
    class="flex items-center justify-between px-4 py-3 border-b border-akong-border bg-white sticky top-0 z-10"
    data-testid="inbox-header"
  >
    <h1 class="text-lg font-semibold" data-testid="inbox-title">{{ title }}</h1>
    <button
      v-if="showRefresh"
      :disabled="loading"
      class="text-xs text-akong-muted disabled:opacity-50 transition-opacity"
      data-testid="refresh-btn"
      @click="$emit('refresh')"
    >
      {{ loading ? '加载中…' : '刷新' }}
    </button>
  </header>
</template>
